import * as React from "react";
import TitleBar from "./TitleBar";
import Window from "./Window";

export default () => {
    return <Window >
        <TitleBar title="Tutorial" />
        <div>
            <p>Hello. Select a food-producing (green) planet to be your starting planet, then unpause the game (button in top-right corner). After you're done, mouse over the user interface, like labels,buttons, tables, to see the tooltips about game concepts, especially the market panel on colonized planets, which explains the game economics. Feel free to click on any colored items on the map, as they are interactive.</p>
            <p>Also, try to change the viewport by panning and pinching, or click-and-drag and mouse wheel zooming if you are playing on a PC.</p>
        </div>
    </Window>;
};



