import * as React from "react";

export const ContentPanel: React.SFC = (props) =>
    <div className="panel-content">
        {props.children}
    </div>;

const Window: React.SFC = (props) => {
    return <div className="panel">
        {props.children}
    </div>;
};

export default Window;



